};

const getComponent = (
  com,
  configuration,
  layer,
  tool,
  component,
  updateConfiguration,
  c,
  inlineHelp,
  value,
  forceField,
  dispatch,
  fieldDefaults
) => {
  const directConf =
    layer == null ? (tool == null ? (component == null ? configuration : component) : tool) : layer;

  // Check if this is a planetary projection component and if TiTiler is available
  const isPlanetaryProjectionComponent = 
    com.field === "projection.tilematrixset" || 
    com.action === "coordinates-populate-from-tmset";
  const isTitilerDisabled = window.mmgisglobal.WITH_TITILER !== "true";
  const isDisabled = isPlanetaryProjectionComponent && isTitilerDisabled;

  // Get the configurable disabled message or use a default
  const disabledMessage = com.disabledMessage || "This feature is disabled.";

  let inner;
  let disabled = com.disabled || false;
  if (com.disableSwitch) {
    let switchVal = getIn(configuration, com.disableSwitch, null);
    if (switchVal == null) {
      // fall back to defaultChecked of the referenced switch if available
      const def = fieldDefaults?.[com.disableSwitch];
      if (def != null && typeof def.defaultChecked === "boolean") {
        switchVal = def.defaultChecked;
      } else {
        switchVal = false;
      }
    }
    disabled = disabled || !switchVal;
  }
  const isRequired = isFieldRequired(com, layer, configuration);
  const fieldValue = value != null ? value : getIn(directConf, com.field, "");
  const hasError = isRequired && (fieldValue === "" || fieldValue == null);

  switch (com.type) {
    case "gap":
      return (
        <div>
          <Typography className={c.subtitle3}>
            {com.description || ""}
          </Typography>
        </div>
      );
    case "text":
      inner = (
        <TextField
          className={c.text}
          label={com.name}
          variant="filled"
          size="small"
          disabled={disabled || isDisabled}
          required={isRequired}
          error={hasError}
          helperText={hasError ? "This field is required" : ""}
          FormHelperTextProps={{
            className: c.noMarginHelperText
          }}
          inputProps={{
            autoComplete: "off",
          }}
          value={fieldValue}
          onChange={(e) => {
            if (!isDisabled) {
              updateConfiguration(forceField || com.field, e.target.value, layer);
            }
          }}
          onBlur={(e) => {
            if (!isDisabled) {
              let v = e.target.value;
              // remove surrounding whitespace, " hi " -> "hi"
              if (typeof v === "string") v = v.trim();
              updateConfiguration(forceField || com.field, v, layer);
            }
          }}
        />
      );
      return (
        <div style={isDisabled ? { opacity: 0.5 } : {}}>
          {inlineHelp ? (
            <>
              {inner}
              <div
                className={c.subtitle2}
                dangerouslySetInnerHTML={{ 
                  __html: isDisabled 
                    ? `${com.description || ""}<br/><strong>Note:</strong> ${disabledMessage}`
                    : com.description || "" 
                }}
              ></div>
            </>
          ) : (
            <Tooltip 
              title={
                isDisabled 
                  ? `${com.description || ""}\n\nNote: ${disabledMessage}`
                  : com.description || ""
              } 
              placement="top" 
              arrow
            >
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "textnotrim":
      inner = (
        <TextField
          className={c.text}
          label={com.name}
          variant="filled"
          size="small"
          disabled={disabled}
          required={isRequired}
          error={hasError}
          helperText={hasError ? "This field is required" : ""}
          FormHelperTextProps={{
            className: c.noMarginHelperText
          }}
          inputProps={{
            autoComplete: "off",
          }}
          value={fieldValue}
          onChange={(e) => {
            updateConfiguration(forceField || com.field, e.target.value, layer);
          }}
        />
      );
      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <div
                className={c.subtitle2}
                dangerouslySetInnerHTML={{ __html: com.description || "" }}
              ></div>
            </>
          ) : (
            <Tooltip title={com.description || ""} placement="top" arrow>
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "button":
      inner = (
        <Button
          className={c.button}
          variant="outlined"
          disabled={isDisabled}
          startIcon={<PrecisionManufacturingIcon />}
          disabled={disabled}
          onClick={() => {
            if (isDisabled) return;
            if (com.action === "tile-populate-from-x") {
              tilePopulateFromX(
                layer.type,
                layer.url,
                layer.demtileurl,
                `Missions/${configuration.msv.mission}/`,
                layer.throughTileServer === true,
                (minZoom, maxNativeZoom, boundingBox) => {
                  let conf = updateConfiguration(
                    "minZoom",
                    minZoom,
                    layer,
                    true
                  );
                  conf = updateConfiguration(
                    "maxNativeZoom",
                    maxNativeZoom,
                    layer,
                    true,
                    conf
                  );

                  conf = updateConfiguration(
                    "maxZoom",
                    maxNativeZoom,
                    layer,
                    true,
                    conf
                  );
                  updateConfiguration(
                    "boundingBox",
                    boundingBox,
                    layer,
                    false,
                    conf
                  );

                  dispatch(
                    setSnackBarText({
                      text: "Successfully populated fields from XML or from cog/info.",
                      severity: "success",
                    })
                  );
                },
                (err) => {
                  dispatch(
                    setSnackBarText({
                      text: "Could not find an XML or cog/info alongside that URL.",
                      severity: "error",
                    })
                  );
                }
              );
            } else if (com.action === "projection-populate-from-x") {
              const inputPath = getIn(configuration, "projection.xmlpath", "");
              if (inputPath == null || inputPath === "") {
                dispatch(
                  setSnackBarText({
                    text: "Please provide a path or URL to tilemapresource.xml or an ArcGIS MapServer (?f=pjson).",
                    severity: "error",
                  })
                );
                return;
              }

              const missionPath = `Missions/${configuration.msv.mission}/`;
              projectionPopulateFromX(inputPath, missionPath)
                .then((vals) => {
                  const { bounds, origin, reszoomlevel, resunitsperpixel } = vals;

                  let conf = updateConfiguration(
                    "projection.bounds",
                    bounds || getIn(configuration, "projection.bounds", null),
                    null,
                    true
                  );
                  if (origin != null) {
                    conf = updateConfiguration(
                      "projection.origin",
                      origin,
                      null,
                      true,
                      conf
                    );
                  }
                  if (reszoomlevel != null) {
                    conf = updateConfiguration(
                      "projection.reszoomlevel",
                      reszoomlevel,
                      null,
                      true,
                      conf
                    );
                  }
                  if (resunitsperpixel != null) {
                    conf = updateConfiguration(
                      "projection.resunitsperpixel",
                      resunitsperpixel,
                      null,
                      true,
                      conf
                    );
                  }

                  // Final dispatch
                  updateConfiguration("projection.bounds", bounds, null, false, conf);

                  dispatch(
                    setSnackBarText({
                      text: "Projection fields populated.",
                      severity: "success",
                    })
                  );
                })
                .catch((err) => {
                  dispatch(
                    setSnackBarText({
                      text: `Failed to populate projection fields: ${err?.message || err}`,
                      severity: "error",
                    })
                  );
                });
            } else if (com.action === "coordinates-populate-from-tmset") {
              const selectedTileMatrixSet = getIn(configuration, ["projection", "tilematrixset"]);

              if (!selectedTileMatrixSet) {
                dispatch(setSnackBarText({
                  text: "Please select a TileMatrixSet first.",
                  severity: "warning"
                }));
                return;
              }

              // Fetch the detailed TileMatrixSet information
              calls.api(
                "titiler_tileMatrixSet",
                { urlReplacements: { tileMatrixSetId: selectedTileMatrixSet } },
                (res) => {
                  const projectionConfig = parseTileMatrixSetCRS(res);

                  if (projectionConfig) {
                    // Update projection configuration
                    let conf = updateConfiguration("projection.custom", true, null, true);
                    conf = updateConfiguration("projection.epsg", projectionConfig.epsg, null, true, conf);
                    conf = updateConfiguration("projection.proj", projectionConfig.proj, null, true, conf);
                    conf = updateConfiguration("projection.bounds.0", projectionConfig.bounds[0], null, true, conf);
                    conf = updateConfiguration("projection.bounds.1", projectionConfig.bounds[1], null, true, conf);
                    conf = updateConfiguration("projection.bounds.2", projectionConfig.bounds[2], null, true, conf);
                    conf = updateConfiguration("projection.bounds.3", projectionConfig.bounds[3], null, true, conf);
                    conf = updateConfiguration("projection.origin.0", projectionConfig.origin[0], null, true, conf);
                    conf = updateConfiguration("projection.origin.1", projectionConfig.origin[1], null, true, conf);
                    conf = updateConfiguration("projection.reszoomlevel", projectionConfig.reszoomlevel, null, true, conf);
                    conf = updateConfiguration("projection.resunitsperpixel", projectionConfig.resunitsperpixel, null, true, conf);

                    // Update planet radius
                    if (projectionConfig.planetRadius) {
                      conf = updateConfiguration("msv.radius.major", projectionConfig.planetRadius, null, true, conf);
                      conf = updateConfiguration("msv.radius.minor", projectionConfig.planetRadius, null, true, conf);
                    }

                    // Apply all changes at once
                    dispatch(setConfiguration(conf));

                    dispatch(setSnackBarText({
                      text: `Projection settings loaded from ${selectedTileMatrixSet}`,
                      severity: "success"
                    }));
                  } else {
                    dispatch(setSnackBarText({
                      text: "Failed to parse TileMatrixSet CRS information.",
                      severity: "error"
                    }));
                  }
                },
                (err) => {
                  dispatch(setSnackBarText({
                    text: "Failed to fetch TileMatrixSet details: " + (err.message || "Unknown error"),
                    severity: "error"
                  }));
                }
              );
            } else if (com.action === "coordinates-apply-to-titiler-layers") {
              const selectedTileMatrixSet = getIn(configuration, ["projection", "tilematrixset"]);

              if (!selectedTileMatrixSet) {
                dispatch(setSnackBarText({
                  text: "Please select a TileMatrixSet first.",
                  severity: "warning"
                }));
                return;
              }

              // Find all layers that use TiTiler and update their tileMatrixSet
              let updatedLayers = 0;
              let conf = JSON.parse(JSON.stringify(configuration));

              traverseLayers(conf.layers, (layer, path, index) => {
                // Check if this layer uses TiTiler
                if (layer.type === "tile" && (layer.throughTileServer === true || layer.sourceType === "COG" || 
                    (layer.url && layer.url.startsWith("stac-collection:")))) {
                  // Update the tileMatrixSet for this layer
                  layer.tileMatrixSet = selectedTileMatrixSet;
                  updatedLayers++;
                }
              });

              if (updatedLayers > 0) {
                dispatch(setConfiguration(conf));
                dispatch(setSnackBarText({
                  text: `Applied ${selectedTileMatrixSet} to ${updatedLayers} TiTiler-enabled layer(s)`,
                  severity: "success"
                }));
              } else {
                dispatch(setSnackBarText({
                  text: "No TiTiler-enabled layers found to update",
                  severity: "info"
                }));
              }
            }
          }}
        >
          {com.name}
        </Button>
      );
      return (
        <div style={isDisabled ? { opacity: 0.5 } : {}}>
          {inlineHelp ? (
            <>
              {inner}
              <div
                className={c.subtitle2}
                dangerouslySetInnerHTML={{ __html: isDisabled 
                  ? `${com.description || ""}\n\nNote: ${disabledMessage}`
                  : com.description || "" }}
              ></div>
            </>
          ) : (
            <Tooltip 
              title={
                isDisabled 
                  ? `${com.description || ""}\n\nNote: ${disabledMessage}`
                  : com.description || ""
              } 
              placement="top" 
              arrow
            >
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "textarray":
      let text_array_f = value != null ? value : getIn(directConf, com.field, []);
      if (text_array_f != null && typeof text_array_f.join === "function")
        text_array_f = text_array_f.join(",");

      // Check if field is required and has validation error
      const textArrayHasError = isRequired && (text_array_f === "" || text_array_f == null || (Array.isArray(text_array_f) && text_array_f.length === 0));

      inner = (
        <TextField
          className={c.text}
          label={com.name}
          variant="filled"
          size="small"
          disabled={disabled}
          required={isRequired}
          error={textArrayHasError}
          helperText={textArrayHasError ? "This field is required" : ""}
          FormHelperTextProps={{
            className: c.noMarginHelperText
          }}
          inputProps={{
            autoComplete: "off",
          }}
          value={text_array_f}
          onChange={(e) => {
            let newValue = null;
            if (e.target.value == null || e.target.value == "") newValue = null;
            else newValue = e.target.value.split(",");

            updateConfiguration(forceField || com.field, newValue, layer);
          }}
        />
      );
      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <div className={c.textArrayHexes}>
                {typeof text_array_f === "string"
                  ? (text_array_f.match(/(#(?:[0-9a-f]{3}){1,2})/gi) || []).map(
                      (hex) => {
                        return (
                          <div
                            className={c.textArrayHex}
                            style={{ background: hex }}
                          ></div>
                        );
                      }
                    )
                  : null}
              </div>
              <Typography className={c.subtitle2}>
                {com.description || ""}
              </Typography>
            </>
          ) : (
            <Tooltip title={com.description || ""} placement="top" arrow>
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "markdown":
      let markdown_f = value || getIn(directConf, com.field, "");
      return (
        <div className="container">
          <MDEditor
            value={markdown_f}
            onChange={(val) => {
              updateConfiguration(forceField || com.field, val, layer);
            }}
            height={500}
          />
        </div>
      );
    case "json":
      let json_f = value || getIn(directConf, com.field, {});
      try {
        if (typeof json_f === "string") json_f = JSON.parse(json_f);
      } catch (err) {}
      return (
        <div className={c.json}>
          <div>
            <Typography className={c.subtitle}>{com.name || ""}</Typography>
            <Typography className={c.subtitle2}>
              {com.description || ""}
            </Typography>
          </div>
          <CodeMirror
            value={JSON.stringify(json_f, null, 2)}
            height={com.height || "300px"}
            extensions={[json()]}
            onChange={(val) => {
              try {
                const v = JSON.parse(val);
                updateConfiguration(forceField || com.field, v, layer);
              } catch (e) {}
            }}
          />
        </div>
      );
    case "number":
      const numberValue = value != null ? value : getIn(directConf, com.field, "");
      const numberHasError = isRequired && (numberValue === "" || numberValue == null || isNaN(numberValue));
      inner = (
        <TextField
          className={c.text}
          label={com.name}
          variant="filled"
          size="small"
          disabled={disabled}
          required={isRequired}
          error={numberHasError}
          helperText={numberHasError ? "This field is required" : ""}
          FormHelperTextProps={{
            className: c.noMarginHelperText
          }}
          inputProps={{
            autoComplete: "off",
          }}
          value={numberValue}
          onChange={(e) => {
            let v = e.target.value;
            if (v != "") {
              const min = com.min != null ? com.min : -Infinity;
              const max = com.max != null ? com.max : Infinity;
              v = Math.max(v, min);
              v = Math.min(v, max);
            }
            updateConfiguration(forceField || com.field, v, layer);
          }}
          type="number"
          min={com.min != null ? com.min : -Infinity}
          step={com.step != null ? com.step : 1}
          max={com.max != null ? com.max : Infinity}
        />
      );
      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <Typography className={c.subtitle2}>
                {com.description || ""}
              </Typography>
            </>
          ) : (
            <Tooltip title={com.description || ""} placement="top" arrow>
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "checkbox":
      inner = (
        <FormGroup className={c.checkbox}>
          <FormControlLabel
            control={
              <Checkbox
                disabled={disabled}
                checked={
                  value != null ? value : getIn(directConf, com.field, com.defaultChecked)
                }
                onChange={(e) => {
                  updateConfiguration(
                    forceField || com.field,
                    e.target.checked,
                    layer
                  );
                }}
              />
            }
            label={com.name}
          />
        </FormGroup>
      );
      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <Typography className={c.subtitle2}>
                {com.description || ""}
              </Typography>
            </>
          ) : (
            <Tooltip title={com.description || ""} placement="top" arrow>
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "slider":
      inner = (
        <Box>
          <Grid container spacing={2} className={c.slider}>
            <Typography className={c.sliderName} id="input-slider" gutterBottom>
              {`${com.name} (${
                value != null
                  ? value
                  : getIn(directConf, com.field, com.default || "")
              })`}
            </Typography>
            <Grid item xs style={{ margin: "0px 10px" }}>
              <Slider
                disabled={disabled}
                value={
                  value != null
                    ? value
                    : getIn(directConf, com.field, com.default || "")
                }
                onChange={(e) => {
                  let v = e.target.value;
                  const min = com.min != null ? com.min : -Infinity;
                  const max = com.max != null ? com.max : Infinity;
                  v = Math.max(v, min);
                  v = Math.min(v, max);
                  updateConfiguration(forceField || com.field, v, layer);
                }}
                min={com.min != null ? com.min : -Infinity}
                step={com.step != null ? com.step : 1}
                max={com.max != null ? com.max : Infinity}
                valueLabelDisplay="auto"
              />
            </Grid>
          </Grid>
        </Box>
      );
      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <Typography className={c.subtitle2}>
                {com.description || ""}
              </Typography>
            </>
          ) : (
            <Tooltip title={com.description || ""} placement="top" arrow>
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "switch":
      inner = (
        <FormGroup className={c.switch}>
          <FormControlLabel
            control={
              <Switch
                disabled={disabled}
                checked={
                  value != null ? value : getIn(directConf, com.field, com.defaultChecked)
                }
                onChange={(e) => {
                  updateConfiguration(
                    forceField || com.field,
                    e.target.checked,
                    layer
                  );
                }}
              />
            }
            label={com.name}
          />
        </FormGroup>
      );
      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <Typography className={c.subtitle2}>
                {com.description || ""}
              </Typography>
            </>
          ) : (
            <Tooltip title={com.description || ""} placement="top" arrow>
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "dropdown":
      inner = (
        <FormControl className={c.dropdown} variant="filled" size="small">
          <InputLabel>{com.name}</InputLabel>
          <Select
            disabled={disabled || isDisabled}
            value={value || getIn(directConf, com.field, com.options?.[0])}
            onChange={(e) => {
              if (!isDisabled) {
                updateConfiguration(
                  forceField || com.field,
                  e.target.value,
                  layer
                );
              }
            }}
          >
            {com.options.map((o) => {
              return (
                <MenuItem value={o}>
                  {typeof o === "string" ? o.toUpperCase() : o}
                </MenuItem>
              );
            })}
          </Select>
        </FormControl>
      );
      return (
        <div style={isDisabled ? { opacity: 0.5 } : {}}>
          {inlineHelp ? (
            <>
              {inner}
              <div
                className={c.subtitle2}
                dangerouslySetInnerHTML={{ __html: isDisabled 
                  ? `${com.description || ""}\n\nNote: ${disabledMessage}`
                  : com.description || "" }}
              ></div>
            </>
          ) : (
            <Tooltip 
              title={
                isDisabled 
                  ? `${com.description || ""}\n\nNote: ${disabledMessage}`
                  : com.description || ""
              } 
              placement="top" 
              arrow
            >
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "searchdropdown":
      let searchOptions = com.options;

      // Support for dynamic injection through mustache
      // Note: This follows the same pattern as the regular dropdown - 
      // the options come pre-processed from the config system
      if (typeof searchOptions === "string") {
        try {
          searchOptions = JSON.parse(searchOptions);
        } catch {
          searchOptions = [searchOptions];
        }
      }

      if (!Array.isArray(searchOptions)) {
        searchOptions = com.options || [];
      }

      const currentValue = value || getIn(directConf, com.field, com.options?.[0] || "");

      inner = (
        <Autocomplete
          className={c.autocomplete}
          disabled={isDisabled}
          options={searchOptions}
          value={currentValue}
          onChange={(event, newValue) => {
            if (!isDisabled && newValue !== null) {
              updateConfiguration(forceField || com.field, newValue, layer);
            }
          }}
          renderInput={(params) => (
            <TextField
              {...params}
              label={com.name}
              variant="filled"
              size="small"
              disabled={isDisabled}
            />
          )}
          renderOption={(props, option) => (
            <li {...props}>
              {typeof option === "string" ? option : option}
            </li>
          )}
          filterOptions={(options, { inputValue }) => {
            return options.filter((option) =>
              option.toLowerCase().includes(inputValue.toLowerCase())
            );
          }}
          noOptionsText="No matching tilematrixsets"
          clearOnBlur={false}
          selectOnFocus
          handleHomeEndKeys
        />
      );
      return (
        <div style={isDisabled ? { opacity: 0.5 } : {}}>
          {inlineHelp ? (
            <>
              {inner}
              <div
                className={c.subtitle2}
                dangerouslySetInnerHTML={{ __html: isDisabled 
                  ? `${com.description || ""}\n\nNote: ${disabledMessage}`
                  : com.description || "" }}
              ></div>
            </>
          ) : (
            <Tooltip 
              title={
                isDisabled 
                  ? `${com.description || ""}\n\nNote: ${disabledMessage}`
                  : com.description || ""
              } 
              placement="top" 
              arrow
            >
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "multiselect":
      let multiOptions = com.options || [];

      // Support for dynamic injection through mustache (same pattern as searchdropdown)
      if (typeof multiOptions === "string") {
        try {
          multiOptions = JSON.parse(multiOptions);
        } catch {
          multiOptions = [multiOptions];
        }
      }

      if (!Array.isArray(multiOptions)) {
        multiOptions = com.options || [];
      }

      // Handle nested field paths properly (e.g., "stateConstraints.allowedStates")
      let multiValue = value;
      if (multiValue == null && forceField) {
        // When in objectarray, use the full path from configuration
        multiValue = getIn(configuration, forceField.split("."), []);
      } else if (multiValue == null) {
        multiValue = getIn(directConf, com.field.split("."), []);
      }
      const normalizedMultiValue = Array.isArray(multiValue) ? multiValue : [];

      inner = (
        <Autocomplete
          multiple
          disabled={disabled}
          options={multiOptions}
          value={normalizedMultiValue}
          onChange={(e, newValue) => {
            updateConfiguration(forceField || com.field, newValue || [], layer);
          }}
          getOptionLabel={(option) => option}
          isOptionEqualToValue={(option, value) => option === value}
          renderOption={(props, option, { selected }) => (
            <li {...props}>
              <Checkbox
                checked={selected}
                style={{ marginRight: 8 }}
              />
              {option}
            </li>
          )}
          renderInput={(params) => (
            <TextField
              {...params}
              label={com.name}
              variant="filled"
              size="small"
              disabled={disabled}
            />
          )}
          disableCloseOnSelect
          ChipProps={{ size: "small" }}
        />
      );
      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <Typography className={c.subtitle2}>
                {com.description || ""}
              </Typography>
            </>
          ) : (
            <Tooltip title={com.description || ""} placement="top" arrow>
              {inner}
            </Tooltip>
          )}
        </div>
      );
    case "colordropdown":
      let dropdown_value =
        value || getIn(directConf, com.field, com.options?.[0]);
      inner = (
        <FormControl className={c.dropdown} variant="filled" size="small">
          <InputLabel>{com.name}</InputLabel>
          <Select
            disabled={disabled}
            value={dropdown_value}
            onChange={(e) => {
              updateConfiguration(
                forceField || com.field,
                e.target.value,
                layer
              );
            }}
          >
            {com.options?.map((o) => {
              return <MenuItem value={o}>{o.toUpperCase()}</MenuItem>;
            })}
          </Select>
        </FormControl>
      );

      let domain =
        window.mmgisglobal.NODE_ENV === "development"
          ? "http://localhost:8888/"
          : window.mmgisglobal.ROOT_PATH || "";
      if (domain.length > 0 && !domain.endsWith("/")) domain += "/";

      let source = "";
      if (window.mmgisglobal.WITH_TITILER === "true") {
        // Get colors from TiTiler if it is available
        source = `${domain}titiler/colorMaps/${dropdown_value.toLowerCase()}?format=png`
      }

      return (
        <div>
          {inlineHelp ? (
            <>
              {inner}
              <div className={c.textArrayHexes}>
