export default function Maker(props) {
  const { config, layer, toolName, componentName, shadowed, inlineHelp } = props;
  const c = useStyles();

  const dispatch = useDispatch();

  const [tabValue, setTabValue] = useState(0);

  const configuration = useSelector((state) => state.core.configuration);

  let tool = null;
  if (toolName) tool = getToolFromConfiguration(toolName, configuration);

  let component = null;
  if (componentName) component = getComponentFromConfiguration(componentName, configuration);

  const updateConfiguration = (
    keyPath,
    value,
    layer,
    returnInstead,
    forceConfig
  ) => {
    const nextConfiguration = JSON.parse(
      JSON.stringify(forceConfig || configuration)
    );

    if (tool != null) {
      updateToolInConfiguration(
        tool.name,
        nextConfiguration,
        keyPath.split("."),
        value
      );
    } else if (component != null) {
      updateComponentInConfiguration(
        component.name,
        nextConfiguration,
        keyPath.split("."),
        value
      );
    } else if (layer != null) {
      traverseLayers(nextConfiguration.layers, (l, path, index) => {
        if (layer.uuid === l.uuid) {
          setIn(l, keyPath.split("."), value, true);
        }
      });
    } else {
      setIn(nextConfiguration, keyPath.split("."), value, true);
    }
    if (returnInstead) return nextConfiguration;
    else dispatch(setConfiguration(nextConfiguration));
  };



  return (
    <div
      className={clsx(c.Maker, { [c.shadowed]: shadowed })}
      style={{ height: config.tabs ? "100%" : "unset" }}
    >
      {config.tabs
        ? makeConfigTabs(config.tabs, tabValue, setTabValue, c)
        : null}
      <div className={clsx({ [c.contentTabs]: config.tabs })}>
        {makeConfig(
          updateConfiguration,
          config.tabs ? config.tabs[tabValue] : config,
          configuration,
          layer,
          tool,
          component,
          c,
          shadowed,
          inlineHelp,
          dispatch
        )}
      </div>
    </div>
  );
}

// Helper funcs
function tilePopulateFromX(
  layerType,
  url,
  demTileUrl,
  missionPath,
  throughTileServer,
  cb,
  errorCallback
) {
  // Tile or Data layer
  // input url or demtileurl
  // input mission path
  // sets, minZoom, maxNativeZoom and boundingBox

  if (throughTileServer) {
    if (layerType === "tile") {
      let fullUrl = url;
      if (!isUrlAbsolute(url)) {
        fullUrl = missionPath.replace("config.json", "") + fullUrl;

        if (window.mmgisglobal.IS_DOCKER !== "true") {
          fullUrl = `../../${fullUrl}`;
        }
      }

      fullUrl = `${window.location.origin}/titiler/cog/info?url=${fullUrl}`;

      fetch(fullUrl)
        .then((response) => response.json())
        .then((json) => {
          try {
            const minZoom = json.minzoom;
            const maxNativeZoom = json.maxzoom;

            let boundingBox = ``;
            if (json.bounds != null)
              boundingBox = `${json.bounds[0]},${json.bounds[1]},${json.bounds[2]},${json.bounds[3]}`;
            cb(minZoom, maxNativeZoom, boundingBox);
          } catch (err) {
            errorCallback(err);
          }
        })
        .catch((err) => {
          errorCallback(err);
        });
    }
  } else {
    let xmlPath = false;
    if (layerType === "tile") xmlPath = url;
    else if (layerType === "data") xmlPath = demTileUrl;

    if (xmlPath == false) {
      ///////////////////////////////////////////////////////////////////////////////
      return;
    }

    xmlPath = xmlPath.replace("{z}/{x}/{y}.png", "tilemapresource.xml");
    xmlPath = missionPath.replace("config.json", "") + xmlPath;
    fetch(xmlPath)
      .then((response) => response.text())
      .then((str) => new window.DOMParser().parseFromString(str, "text/xml"))
      .then((xml) => {
        try {
          const tLen = xml.getElementsByTagName("TileSet").length;
          const minZoom =
            xml.getElementsByTagName("TileSet")[0].attributes["order"].value;
          const maxNativeZoom =
            xml.getElementsByTagName("TileSet")[tLen - 1].attributes["order"]
              .value;
          const boundingBox =
            xml.getElementsByTagName("BoundingBox")[0].attributes["minx"]
              .value +
            "," +
            xml.getElementsByTagName("BoundingBox")[0].attributes["miny"]
              .value +
            "," +
            xml.getElementsByTagName("BoundingBox")[0].attributes["maxx"]
              .value +
            "," +
            xml.getElementsByTagName("BoundingBox")[0].attributes["maxy"].value;

          cb(
            parseInt(minZoom),
            parseInt(maxNativeZoom),
            boundingBox.split(",")
          );
        } catch (err) {
          errorCallback(err);
        }
      })
      .catch((err) => {
        errorCallback(err);
      });
  }
}

function projectionPopulateFromX(pathOrUrl, missionPath) {
  return new Promise((resolve, reject) => {
    const isAbsolute = isUrlAbsolute(pathOrUrl);
    const isXmlLike = /tilemapresource\.xml$/i.test(pathOrUrl) || /\.xml$/i.test(pathOrUrl);
    const isEsri = /mapserver/i.test(pathOrUrl);

    let fullUrl = pathOrUrl;
    if (!isAbsolute && !isEsri) {
      fullUrl = missionPath.replace("config.json", "") + fullUrl;
      if (window.mmgisglobal.IS_DOCKER !== "true") {
        fullUrl = `../../${fullUrl}`;
      }
    }

    if (isXmlLike && !isEsri) {
      fetch(fullUrl)
        .then((response) => {
          if (!response.ok) throw new Error(`HTTP ${response.status}`);
          return response.text();
        })
        .then((str) => new window.DOMParser().parseFromString(str, "text/xml"))
        .then((xml) => {
          try {
            const bboxEl = xml.getElementsByTagName("BoundingBox")[0];
            const bounds = bboxEl
              ? [
                  parseFloat(bboxEl.getAttribute("minx")),
                  parseFloat(bboxEl.getAttribute("miny")),
                  parseFloat(bboxEl.getAttribute("maxx")),
                  parseFloat(bboxEl.getAttribute("maxy")),
                ]
              : null;

            let origin = null;
            const originEl = xml.getElementsByTagName("Origin")[0];
            if (originEl) {
              origin = [
                parseFloat(originEl.getAttribute("x")),
                parseFloat(originEl.getAttribute("y")),
              ];
            }

            const tileSets = xml.getElementsByTagName("TileSet");
            let reszoomlevel = null;
            let resunitsperpixel = null;
            if (tileSets && tileSets.length > 0) {
              // Prefer order 0 if present; otherwise first
              let chosen = tileSets[0];
              for (let i = 0; i < tileSets.length; i++) {
                const o = parseInt(tileSets[i].getAttribute("order"));
                if (!isNaN(o) && o === 0) {
                  chosen = tileSets[i];
                  break;
                }
              }
              const o = chosen.getAttribute("order");
              const upp = chosen.getAttribute("units-per-pixel");
              if (o != null) reszoomlevel = parseInt(o);
              if (upp != null) resunitsperpixel = parseFloat(upp);
            }

            resolve({ bounds, origin, reszoomlevel, resunitsperpixel });
          } catch (err) {
            reject(err);
          }
        })
        .catch((err) => reject(err));
    } else {
      // Treat as ArcGIS MapServer JSON
      try {
        let url = fullUrl;
        if (!/\?/.test(url)) url += "?f=pjson";
        else if (!/[?&]f=pjson/i.test(url)) url += "&f=pjson";

        fetch(url)
          .then((response) => {
            if (!response.ok) throw new Error(`HTTP ${response.status}`);
            return response.json();
          })
          .then((json) => {
            try {
              const extent = json.fullExtent || json.initialExtent;
              const bounds = extent
                ? [
                    parseFloat(extent.xmin),
                    parseFloat(extent.ymin),
                    parseFloat(extent.xmax),
                    parseFloat(extent.ymax),
                  ]
                : null;

              let origin = null;
              if (json.tileInfo && json.tileInfo.origin) {
                origin = [
                  parseFloat(json.tileInfo.origin.x),
                  parseFloat(json.tileInfo.origin.y),
                ];
              }

              let reszoomlevel = null;
              let resunitsperpixel = null;
              const lods = json.tileInfo && json.tileInfo.lods;
              if (lods && lods.length > 0) {
                let chosen = lods.find((l) => l.level === 0);
                if (!chosen) {
                  chosen = lods.slice().sort((a, b) => a.level - b.level)[0];
                }
                reszoomlevel = chosen.level;
                resunitsperpixel = chosen.resolution;
              }

              resolve({ bounds, origin, reszoomlevel, resunitsperpixel });
            } catch (err) {
              reject(err);
            }
          })
          .catch((err) => reject(err));
      } catch (err) {
        reject(err);
      }
    }
  });
}

