const makeConfigTabs = (tabs, value, onChange, c) => {
  if (tabs) {
    return (
      <Tabs
        className={c.tabs}
        value={value}
        onChange={(e, v) => {
          onChange(v);
        }}
        variant="scrollable"
        scrollButtons="auto"
        aria-label="scrollable auto tabs example"
      >
        {tabs.map((tab) => (
          <Tab label={tab.name} />
        ))}
      </Tabs>
    );
  }
};

const makeConfig = (
  updateConfiguration,
  config,
  configuration,
  layer,
  tool,
  component,
  c,
  shadowed,
  inlineHelp,
  dispatch
) => {
  const made = [];

  if (config == null || config.rows == null) return made;

  config.rows.forEach((row, idx) => {
    if (row.name) {
      made.push(
        <div
          className={clsx(c.rowTitle, "rowTitle", {
            [c.rowTitleBasic]: !shadowed,
          })}
          key={`${idx}_title`}
        >
          {row.name}
        </div>
      );
      if (row.description) {
        made.push(
          <div
            className={clsx(c.rowDescription)}
            key={`${idx}_desc`}
            dangerouslySetInnerHTML={{ __html: row.description || "" }}
          ></div>
        );
      }
    }
    if (row.subname) {
      made.push(
        <div
          className={clsx(c.rowSubTitle, { [c.rowTitleBasic]: !shadowed })}
          key={`${idx}_title`}
        >
          {row.subname}
        </div>
      );
      if (row.subdescription) {
        made.push(
          <div
            className={clsx(c.rowDescription)}
            key={`${idx}_desc`}
            dangerouslySetInnerHTML={{ __html: row.subdescription || "" }}
          ></div>
        );
      }
    }
    if (row.components) {
      made.push(
        (() => {
          // Build a lookup of defaultChecked for switches to support disableSwitch fallbacks
          const fieldDefaults = {};
          row.components.forEach((com) => {
            if (com.type === "switch" && typeof com.field === "string") {
              fieldDefaults[com.field] = {
                defaultChecked: com.defaultChecked,
              };
            }
          });

          return (
            <Box
              sx={{ flexGrow: 1 }}
              className={clsx(c.row, { [c.rowBasic]: !shadowed })}
              key={idx}
            >
              <Grid
                container
                spacing={4}
                direction="row"
                justifyContent="left"
                alignItems="left"
                style={row.forceHeight ? { height: row.forceHeight } : null}
              >
                {row.components.map((com, idx2) => {
              return (
                <Grid
                  item
                  xs={com.width || 4}
                  md={com.width || 4}
                  lg={com.width || 4}
                  xl={com.width || 4}
                  key={`${idx}-${idx2}`}
                >
                  {getComponent(
                    com,
                    configuration,
                    layer,
                    tool,
                    component,
                    updateConfiguration,
                    c,
                    inlineHelp,
                    null,
                    null,
                    dispatch,
                    fieldDefaults
                  )}
                </Grid>
              );
                })}
              </Grid>
            </Box>
          );
        })()
      );
    }
  });

  return made;
};

export default function Maker(props) {
  const { config, layer, toolName, componentName, shadowed, inlineHelp } = props;
  const c = useStyles();

  const dispatch = useDispatch();

  const [tabValue, setTabValue] = useState(0);

  const configuration = useSelector((state) => state.core.configuration);

  let tool = null;
  if (toolName) tool = getToolFromConfiguration(toolName, configuration);

  let component = null;
  if (componentName) component = getComponentFromConfiguration(componentName, configuration);

  const updateConfiguration = (
    keyPath,
    value,
    layer,
    returnInstead,
    forceConfig
  ) => {
    const nextConfiguration = JSON.parse(
      JSON.stringify(forceConfig || configuration)
    );

    if (tool != null) {
      updateToolInConfiguration(
        tool.name,
        nextConfiguration,
        keyPath.split("."),
        value
      );
    } else if (component != null) {
      updateComponentInConfiguration(
        component.name,
        nextConfiguration,
        keyPath.split("."),
        value
      );
    } else if (layer != null) {
      traverseLayers(nextConfiguration.layers, (l, path, index) => {
        if (layer.uuid === l.uuid) {
          setIn(l, keyPath.split("."), value, true);
        }
      });
    } else {
      setIn(nextConfiguration, keyPath.split("."), value, true);
    }
    if (returnInstead) return nextConfiguration;
    else dispatch(setConfiguration(nextConfiguration));
  };



  return (
    <div
      className={clsx(c.Maker, { [c.shadowed]: shadowed })}
      style={{ height: config.tabs ? "100%" : "unset" }}
    >
      {config.tabs
        ? makeConfigTabs(config.tabs, tabValue, setTabValue, c)
        : null}
      <div className={clsx({ [c.contentTabs]: config.tabs })}>
        {makeConfig(
          updateConfiguration,
          config.tabs ? config.tabs[tabValue] : config,
          configuration,
          layer,
          tool,
          component,
          c,
          shadowed,
          inlineHelp,
          dispatch
        )}
      </div>
    </div>
  );
}

// Helper funcs
function tilePopulateFromX(
  layerType,
  url,
  demTileUrl,
  missionPath,
  throughTileServer,
  cb,
  errorCallback
) {
  // Tile or Data layer
  // input url or demtileurl
  // input mission path
  // sets, minZoom, maxNativeZoom and boundingBox

  if (throughTileServer) {
    if (layerType === "tile") {
      let fullUrl = url;
      if (!isUrlAbsolute(url)) {
        fullUrl = missionPath.replace("config.json", "") + fullUrl;

        if (window.mmgisglobal.IS_DOCKER !== "true") {
          fullUrl = `../../${fullUrl}`;
        }
      }

      fullUrl = `${window.location.origin}/titiler/cog/info?url=${fullUrl}`;

      fetch(fullUrl)
        .then((response) => response.json())
        .then((json) => {
          try {
            const minZoom = json.minzoom;
            const maxNativeZoom = json.maxzoom;

            let boundingBox = ``;
            if (json.bounds != null)
              boundingBox = `${json.bounds[0]},${json.bounds[1]},${json.bounds[2]},${json.bounds[3]}`;
            cb(minZoom, maxNativeZoom, boundingBox);
          } catch (err) {
            errorCallback(err);
          }
        })
        .catch((err) => {
          errorCallback(err);
        });
    }
  } else {
    let xmlPath = false;
    if (layerType === "tile") xmlPath = url;
    else if (layerType === "data") xmlPath = demTileUrl;

    if (xmlPath == false) {
      ///////////////////////////////////////////////////////////////////////////////
      return;
    }

    xmlPath = xmlPath.replace("{z}/{x}/{y}.png", "tilemapresource.xml");
    xmlPath = missionPath.replace("config.json", "") + xmlPath;
    fetch(xmlPath)
      .then((response) => response.text())
      .then((str) => new window.DOMParser().parseFromString(str, "text/xml"))
      .then((xml) => {
        try {
          const tLen = xml.getElementsByTagName("TileSet").length;
          const minZoom =
            xml.getElementsByTagName("TileSet")[0].attributes["order"].value;
          const maxNativeZoom =
            xml.getElementsByTagName("TileSet")[tLen - 1].attributes["order"]
              .value;
          const boundingBox =
            xml.getElementsByTagName("BoundingBox")[0].attributes["minx"]
              .value +
            "," +
            xml.getElementsByTagName("BoundingBox")[0].attributes["miny"]
              .value +
            "," +
            xml.getElementsByTagName("BoundingBox")[0].attributes["maxx"]
              .value +
            "," +
            xml.getElementsByTagName("BoundingBox")[0].attributes["maxy"].value;

          cb(
            parseInt(minZoom),
            parseInt(maxNativeZoom),
            boundingBox.split(",")
          );
        } catch (err) {
          errorCallback(err);
        }
      })
      .catch((err) => {
        errorCallback(err);
      });
  }
}

function projectionPopulateFromX(pathOrUrl, missionPath) {
  return new Promise((resolve, reject) => {
    const isAbsolute = isUrlAbsolute(pathOrUrl);
    const isXmlLike = /tilemapresource\.xml$/i.test(pathOrUrl) || /\.xml$/i.test(pathOrUrl);
    const isEsri = /mapserver/i.test(pathOrUrl);

    let fullUrl = pathOrUrl;
    if (!isAbsolute && !isEsri) {
      fullUrl = missionPath.replace("config.json", "") + fullUrl;
      if (window.mmgisglobal.IS_DOCKER !== "true") {
        fullUrl = `../../${fullUrl}`;
      }
    }

    if (isXmlLike && !isEsri) {
      fetch(fullUrl)
        .then((response) => {
          if (!response.ok) throw new Error(`HTTP ${response.status}`);
          return response.text();
        })
        .then((str) => new window.DOMParser().parseFromString(str, "text/xml"))
        .then((xml) => {
          try {
            const bboxEl = xml.getElementsByTagName("BoundingBox")[0];
            const bounds = bboxEl
              ? [
                  parseFloat(bboxEl.getAttribute("minx")),
                  parseFloat(bboxEl.getAttribute("miny")),
                  parseFloat(bboxEl.getAttribute("maxx")),
                  parseFloat(bboxEl.getAttribute("maxy")),
                ]
              : null;

            let origin = null;
            const originEl = xml.getElementsByTagName("Origin")[0];
            if (originEl) {
              origin = [
                parseFloat(originEl.getAttribute("x")),
                parseFloat(originEl.getAttribute("y")),
              ];
            }

            const tileSets = xml.getElementsByTagName("TileSet");
            let reszoomlevel = null;
            let resunitsperpixel = null;
            if (tileSets && tileSets.length > 0) {
              // Prefer order 0 if present; otherwise first
              let chosen = tileSets[0];
              for (let i = 0; i < tileSets.length; i++) {
                const o = parseInt(tileSets[i].getAttribute("order"));
                if (!isNaN(o) && o === 0) {
                  chosen = tileSets[i];
                  break;
                }
              }
              const o = chosen.getAttribute("order");
              const upp = chosen.getAttribute("units-per-pixel");
              if (o != null) reszoomlevel = parseInt(o);
              if (upp != null) resunitsperpixel = parseFloat(upp);
            }

            resolve({ bounds, origin, reszoomlevel, resunitsperpixel });
          } catch (err) {
            reject(err);
          }
        })
        .catch((err) => reject(err));
    } else {
      // Treat as ArcGIS MapServer JSON
      try {
        let url = fullUrl;
        if (!/\?/.test(url)) url += "?f=pjson";
        else if (!/[?&]f=pjson/i.test(url)) url += "&f=pjson";

        fetch(url)
          .then((response) => {
            if (!response.ok) throw new Error(`HTTP ${response.status}`);
            return response.json();
          })
          .then((json) => {
            try {
              const extent = json.fullExtent || json.initialExtent;
              const bounds = extent
                ? [
                    parseFloat(extent.xmin),
                    parseFloat(extent.ymin),
                    parseFloat(extent.xmax),
                    parseFloat(extent.ymax),
                  ]
                : null;

              let origin = null;
              if (json.tileInfo && json.tileInfo.origin) {
                origin = [
                  parseFloat(json.tileInfo.origin.x),
                  parseFloat(json.tileInfo.origin.y),
                ];
              }

              let reszoomlevel = null;
              let resunitsperpixel = null;
              const lods = json.tileInfo && json.tileInfo.lods;
              if (lods && lods.length > 0) {
                let chosen = lods.find((l) => l.level === 0);
                if (!chosen) {
                  chosen = lods.slice().sort((a, b) => a.level - b.level)[0];
                }
                reszoomlevel = chosen.level;
                resunitsperpixel = chosen.resolution;
              }

              resolve({ bounds, origin, reszoomlevel, resunitsperpixel });
            } catch (err) {
              reject(err);
            }
          })
          .catch((err) => reject(err));
      } catch (err) {
        reject(err);
      }
    }
  });
}

import React from 'react'
import { createRoot, type Root } from 'react-dom/client'
import { MMGISCardAdapter } from './MMGISCardAdapter'
import { mmgisRequest } from './adapters/mmgisAPI'

type ToolVars = { width?: number }

let _root: Root | null = null

const CardTool = {
    height: 0,
    width: 368 as number | 'full',
    vars: {} as ToolVars,
    targetId: null as string | null,
    made: false,

    initialize: async function () {
        try {
            const isMobile = await mmgisRequest<boolean>('app:isMobile')
            if (isMobile) {
                this.width = 'full'
                this.height = 500
            }
        } catch (err) {
            console.warn(
                '[CardTool] app:isMobile unavailable:',
                err instanceof Error ? err.message : err,
            )
        }
    },

    make: function (targetId?: string) {
        this.targetId = typeof targetId === 'string' ? targetId : 'toolPanel'
        const container = document.getElementById(this.targetId)
        if (!container) {
            console.error(`CardTool: container ${this.targetId} not found`)
            return
        }
        // Don't force the classic dark panel background (var(--color-k) = #1d1f20).
        // In a themed modern panel that dark color shows through the card-list
        // padding/gaps as a dark frame around the light cards. Let the panel's
        // themed background show instead.
        _root = createRoot(container)
        _root.render(<MMGISCardAdapter />)
        this.made = true
    },

    destroy: function () {
        if (_root) {
            _root.unmount()
            _root = null
        }
        this.targetId = null
        this.made = false
    },

    getUrlString: function () {
        return ''
    },
}

export default CardTool

import React from 'react'
import { useState, useCallback } from 'react'
import { CardList } from './lib'
import type { CardItem } from './lib/types'
import { useMMGISHandlerReady } from './adapters/useMMGISHandlerReady'
import { getCardData } from './adapters/getCardData'

export function MMGISCardAdapter() {
    const [cards, setCards] = useState<CardItem[]>([])
    const [loading, setLoading] = useState(true)

    const refresh = useCallback(async () => {
        try {
            setCards(await getCardData())
        } catch (err) {
            console.error('Card: refresh failed', err)
            setCards([])
        } finally {
            setLoading(false)
        }
    }, [])

    // 'tool:getVars' is registered by Layers_.fina() during mission load. Wait
    // for it before the initial fetch, otherwise the adapter mounts to an empty
    // list and never recovers (no event fires when vars first become available).
    useMMGISHandlerReady('tool:getVars', refresh)

    return <CardList cards={cards} loading={loading} />
}

import { mmgisRequest } from './mmgisAPI'
import { buildCardData, type RawCard } from './buildCardData'
import type { CardItem } from '../lib/types'

type CardToolVars = { cards?: RawCard[] }

// Orchestrator: pulls the configured cards (tool vars) and the mission path
// from the MMGIS event bus, then transforms them into renderable lib props.
export async function getCardData(): Promise<CardItem[]> {
    const vars =
        (await mmgisRequest<CardToolVars>('tool:getVars', 'card')) || {}
    const missionPath = await mmgisRequest<string>('app:getMissionPath')
    return buildCardData(vars.cards, typeof missionPath === 'string' ? missionPath : null)
}

import type { CardItem } from '../lib/types'

// Raw card shape as stored in the tool's config variables.
export type RawCard = {
    image?: string
    title?: string
    subtitle?: string
    linkUrl?: string
}

// Resolves a stored card image value to a renderable URL.
// Mission-relative paths (e.g. "CardPlugin/uploads/a.png") are prefixed with
// the mission path (e.g. "Missions/MSL/"); absolute/data/root-relative URLs
// pass through unchanged.
export function resolveImageUrl(
    image: string | undefined | null,
    missionPath: string | null,
): string {
    if (!image) return ''
    if (/^(https?:|data:|\/)/i.test(image)) return image
    return (missionPath || '') + image
}

// Pure transform: raw config cards + mission path -> renderable lib props.
export function buildCardData(
    cards: RawCard[] | undefined,
    missionPath: string | null,
): CardItem[] {
    if (!Array.isArray(cards)) return []
    return cards.map((card) => ({
        imageUrl: resolveImageUrl(card.image, missionPath),
        title: card.title,
        subtitle: card.subtitle,
        linkUrl: card.linkUrl,
    }))
}

type EventCleanup = () => void

type MMGISAPI = {
    request: (name: string, params?: unknown) => Promise<unknown>
    on: (event: string, handler: (payload?: unknown) => void) => EventCleanup
    emit: (event: string, payload?: unknown) => void
    provide?: (name: string, handler: (...args: unknown[]) => unknown) => EventCleanup
    hasHandler?: (name: string) => boolean
}

declare global {
    interface Window {
        mmgisAPI?: MMGISAPI
    }
}

export const mmgisRequest = async <T = unknown>(name: string, params?: unknown): Promise<T | null> => {
    if (window.mmgisAPI?.request) {
        return (await window.mmgisAPI.request(name, params)) as T
    }
    return null
}

export const mmgisOn = (event: string, handler: (payload?: unknown) => void): EventCleanup => {
    if (!window.mmgisAPI?.on) return () => {}
    return window.mmgisAPI.on(event, handler)
}

export const mmgisEmit = (event: string, payload?: unknown): void => {
    window.mmgisAPI?.emit?.(event, payload)
}

export const mmgisProvide = (name: string, handler: (...args: unknown[]) => unknown): EventCleanup => {
    if (!window.mmgisAPI?.provide) return () => {}
    return window.mmgisAPI.provide(name, handler)
}

export const mmgisHasHandler = (name: string): boolean => {
    return window.mmgisAPI?.hasHandler?.(name) === true
}

import { useEffect } from 'react'
import { mmgisHasHandler } from './mmgisAPI'

/**
 * Polls mmgisAPI.hasHandler(name) until it returns true, then invokes onReady once.
 *
 * Use when a mmgisAPI capability is registered asynchronously during MMGIS boot
 * (e.g. Layers_.fina() registers 'layers:getAll' etc. only after the mission's
 * layers are loaded). Without this, components that request a not-yet-registered
 * handler at mount silently get null/empty results.
 *
 * Stops after `timeoutMs` if the handler never appears (with a console warning).
 */
export const useMMGISHandlerReady = (
    handlerName: string,
    onReady: () => void,
    options: { intervalMs?: number; timeoutMs?: number } = {},
): void => {
    const { intervalMs = 200, timeoutMs = 10000 } = options
    useEffect(() => {
        if (mmgisHasHandler(handlerName)) {
            onReady()
            return
        }
        const start = Date.now()
        const id = window.setInterval(() => {
            if (mmgisHasHandler(handlerName)) {
                window.clearInterval(id)
                onReady()
            } else if (Date.now() - start > timeoutMs) {
                window.clearInterval(id)
                console.warn(
                    `[useMMGISHandlerReady] '${handlerName}' not registered after ${timeoutMs}ms`,
                )
            }
        }, intervalMs)
        return () => window.clearInterval(id)
    }, [handlerName, onReady, intervalMs, timeoutMs])
}

// A single card ready to render (image already resolved to a URL).
export type CardItem = {
    imageUrl: string
    title?: string
    subtitle?: string
    linkUrl?: string
}

import React from 'react'
import type { CardItem } from '../../types'

export type CardProps = CardItem

export function Card({ imageUrl, title, subtitle, linkUrl }: CardProps) {
    if (!title && !imageUrl) return null
    return (
        <a
            className="blocks-card"
            href={linkUrl || undefined}
            target="_blank"
            rel="noopener noreferrer"
        >
            {imageUrl ? (
                <img className="blocks-card__image" src={imageUrl} alt={title || ''} />
            ) : (
                <div className="blocks-card__image" />
            )}
            <div className="blocks-card__body">
                {title ? <div className="blocks-card__title">{title}</div> : null}
                {subtitle ? (
                    <div className="blocks-card__subtitle">{subtitle}</div>
                ) : null}
            </div>
        </a>
    )
}

import React from 'react'
import { Card } from '../Card/Card'
import type { CardItem } from '../../types'

export type CardListProps = {
    /** Cards to render (image already resolved to a URL). */
    cards: CardItem[]
    /** Suppresses rendering until the first data load resolves. */
    loading?: boolean
}

export function CardList({ cards, loading }: CardListProps) {
    if (loading) return null
    return (
        <div className="blocks-card-list">
            {cards.map((card, i) => (
                <Card
                    key={i}
                    imageUrl={card.imageUrl}
                    title={card.title}
                    subtitle={card.subtitle}
                    linkUrl={card.linkUrl}
                />
            ))}
        </div>
    )
}

